// packages/core/src/components/client/Dropdown/Dropdown.test.tsx
// Generated by AI (DoXYZ agents). Do not edit directly.
// Summary: Verifies Dropdown trigger semantics, icon slots, Popover open/change handling, and panel placement tokens/classes.

import '@testing-library/jest-dom';
import * as React from 'react';
import { render, screen, waitFor } from '@testing-library/react';
import type { RenderResult } from '@testing-library/react';
import userEvent from '@testing-library/user-event';

import { ArrowDropDownIcon } from '../../../icons';
import { Dropdown } from './Dropdown';

const panelContent = (
  <div>
    <button type="button">Edit</button>
    <button type="button">Duplicate</button>
  </div>
);

describe('Dropdown', () => {
  it('renders the trigger button label with default aria attributes', () => {
    const view: RenderResult = render(<Dropdown label="Actions">{panelContent}</Dropdown>);
    const trigger = screen.getByRole('button', { name: 'Actions' });
    const result = {
      popup: trigger.getAttribute('aria-haspopup'),
      expanded: trigger.getAttribute('aria-expanded'),
      minWidth: trigger.className.includes('min-w-160')
    };
    expect(result).toEqual({
      popup: 'menu',
      expanded: 'false',
      minWidth: true
    });
    view.unmount();
  });

  it('opens the panel on click and notifies onOpenChange', async () => {
    const handleOpenChange = jest.fn<void, [boolean]>();
    const user = userEvent.setup();
    const view: RenderResult = render(
      <Dropdown label="More" onOpenChange={handleOpenChange}>
        {panelContent}
      </Dropdown>
    );
    const trigger = screen.getByRole('button', { name: 'More' });
    await user.click(trigger);
    const panel = await screen.findByText('Edit');
    await waitFor(() => {
      const result = {
        panelTag: panel.tagName,
        expanded: trigger.getAttribute('aria-expanded'),
        calls: handleOpenChange.mock.calls
      };
      expect(result).toEqual({
        panelTag: 'DIV',
        expanded: 'true',
        calls: [[true]]
      });
    });
    view.unmount();
  });

  it('renders provided icon slots on the trigger button', () => {
    const view: RenderResult = render(
      <Dropdown
        label="Icons"
        startIcon={<ArrowDropDownIcon aria-hidden="true" data-testid="start" />}
        endIcon={<ArrowDropDownIcon aria-hidden="true" data-testid="end" />}
      >
        {panelContent}
      </Dropdown>
    );
    const startIcon = screen.getByTestId('start');
    const endIcon = screen.getByTestId('end');
    expect({ startTag: startIcon.tagName, endTag: endIcon.tagName }).toEqual({
      startTag: 'svg',
      endTag: 'svg'
    });
    view.unmount();
  });

  it('applies placement props to the panel', async () => {
    const user = userEvent.setup();
    const view: RenderResult = render(
      <Dropdown label="Placement" align="end" side="top" sideOffset={12}>
        {panelContent}
      </Dropdown>
    );
    const trigger = screen.getByRole('button', { name: 'Placement' });
    await user.click(trigger);
    const content = await screen.findByText('Edit');
    const result = {
      hasBorder: content.className.includes('border'),
      hasPadding: content.className.includes('p-2'),
      align: content.getAttribute('data-align'),
      side: content.getAttribute('data-side')
    };
    expect(result).toEqual({
      hasBorder: true,
      hasPadding: true,
      align: 'end',
      side: 'top'
    });
    view.unmount();
  });

  it('closes on Escape and returns focus to the trigger', async () => {
    const user = userEvent.setup();
    const view: RenderResult = render(<Dropdown label="Escape">{panelContent}</Dropdown>);
    const trigger = screen.getByRole('button', { name: 'Escape' });
    await user.click(trigger);
    await screen.findByText('Edit');
    await user.keyboard('{Escape}');
    await waitFor(() => {
      const result = {
        panelOpen: screen.queryByText('Edit') !== null,
        focusReturned: document.activeElement === trigger
      };
      expect(result).toEqual({
        panelOpen: false,
        focusReturned: true
      });
    });
    view.unmount();
  });

  it('does not open when disabled', async () => {
    const user = userEvent.setup();
    const view: RenderResult = render(
      <Dropdown label="Locked" disabled>
        {panelContent}
      </Dropdown>
    );
    const trigger = screen.getByRole('button', { name: 'Locked' });
    await user.click(trigger);
    const result = {
      panelVisible: screen.queryByText('Edit') !== null,
      disabledAttr: trigger.hasAttribute('disabled')
    };
    expect(result).toEqual({
      panelVisible: false,
      disabledAttr: true
    });
    view.unmount();
  });

  it('respects controlled open state', async () => {
    const handleOpenChange = jest.fn<void, [boolean]>();
    const user = userEvent.setup();
    const { rerender } = render(
      <Dropdown label="Controlled" open={false} onOpenChange={handleOpenChange}>
        {panelContent}
      </Dropdown>
    );
    const trigger = screen.getByRole('button', { name: 'Controlled' });
    await user.click(trigger);
    const panelClosedInitially = screen.queryByText('Edit') === null;
    rerender(
      <Dropdown label="Controlled" open={true} onOpenChange={handleOpenChange}>
        {panelContent}
      </Dropdown>
    );
    const panel = await screen.findByText('Edit');
    await user.keyboard('{Escape}');
    await waitFor(() => {
      const result = {
        panelClosedInitially,
        callSequence: handleOpenChange.mock.calls,
        panelRendered: panel !== null,
        panelClosed: screen.queryByText('Edit') === null,
        lastCall: handleOpenChange.mock.calls[handleOpenChange.mock.calls.length - 1]
      };
      expect(result).toEqual({
        panelClosedInitially: true,
        callSequence: [[true], [false]],
        panelRendered: true,
        panelClosed: true,
        lastCall: [false]
      });
    });
  });
});
